    const std::vector<int>& heuristic
) {
    std::priority_queue<Node, std::vector<Node>, std::greater<Node>> pq;
    std::vector<bool> visited(n, false);
    std::vector<int> parent(n, -1);

    pq.push({start, heuristic[start]});
    visited[start] = true;

    bool found = false;

    while (!pq.empty()) {
        Node current = pq.top();
        pq.pop();
        int u = current.id;

        if (u == target) {
            found = true;
            break;
        }

        for (int v : adj[u]) {
            if (!visited[v]) {
                visited[v] = true;
                parent[v] = u;
                pq.push({v, heuristic[v]});
            }
        }
    }

    std::vector<int> path;
    if (found) {
        int curr = target;
        while (curr != -1) {
            path.push_back(curr);
            curr = parent[curr];
        }
        std::reverse(path.begin(), path.end());
    }
    return path;
}

