            var path: [Int] = []
            var curr = target
            while curr != -1 {
                path.append(curr)
                curr = parent[curr]
            }
            return path.reversed()
        }

        return []
    }
}

interface QueueEntry {
  node: number;
  path: number[];
}

export function bestFirstSearch(
  adjacencyList: Record<number, number[]>,
  start: number,
  goal: number,
  heuristic: Record<number, number>,
): number[] {
  if (start === goal) {
    return [start];
  }

  const visited = new Set<number>();
  const queue: QueueEntry[] = [{ node: start, path: [start] }];

  while (queue.length > 0) {
    queue.sort((a, b) => (heuristic[a.node] ?? Number.MAX_SAFE_INTEGER) - (heuristic[b.node] ?? Number.MAX_SAFE_INTEGER));
    const current = queue.shift();
    if (!current) {
      break;
    }
    if (visited.has(current.node)) {
      continue;
    }
    visited.add(current.node);

    for (const neighbor of adjacencyList[current.node] ?? []) {
      const nextPath = [...current.path, neighbor];
      if (neighbor === goal) {
        return nextPath;
      }
      if (!visited.has(neighbor)) {
        queue.push({ node: neighbor, path: nextPath });
      }
    }
  }

  return [];
}

interface Entry {
    node: number;
    heuristic: number;
    path: number[];
}

export function bestFirstSearch(
    adj: Record<number, number[]>,
    start: number,
    goal: number,
    heuristic: Record<number, number>
): number[] {
    if (start === goal) {
        return [start];
    }

    const visited = new Set<number>();
    // Simple priority queue using array with manual min extraction
    const pq: Entry[] = [];

    pq.push({ node: start, heuristic: heuristic[start], path: [start] });

    while (pq.length > 0) {
        // Find entry with minimum heuristic
        let minIndex = 0;
        for (let i = 1; i < pq.length; i++) {
            if (pq[i].heuristic < pq[minIndex].heuristic) {
                minIndex = i;
            }
        }
        const current = pq.splice(minIndex, 1)[0];

        if (current.node === goal) {
            return current.path;
        }

        if (visited.has(current.node)) {
            continue;
        }
        visited.add(current.node);

        const neighbors = adj[current.node] || [];
        for (const neighbor of neighbors) {
            if (!visited.has(neighbor)) {
                pq.push({
                    node: neighbor,
                    heuristic: heuristic[neighbor],
                    path: [...current.path, neighbor],
                });
            }
        }
    }

    return [];
}

const adj: Record<number, number[]> = { 0: [1, 2], 1: [3], 2: [3], 3: [] };
const heuristic: Record<number, number> = { 0: 6, 1: 3, 2: 4, 3: 0 };
const result = bestFirstSearch(adj, 0, 3, heuristic);
